(window.webpackJsonp=window.webpackJsonp||[]).push([[263],{890:function(n,t){n.exports="\x3c!-- \ntitle: 03-React脚手架\nsort: \n--\x3e \n\n```bash\nsrc\n|_ App.css\n|_ App.js\n|_ index.js\n|_ App.js\n|_ App.js\n```\n\n## Sass\n\n> css扩展\n>\n> `Syntactically Awesome Style Sheets`\n\n```scss\ndiv{\n  text-align: center;\n  h1 {\n    color: red;\n    font-size: 30px;\n  }\n}\n```\n\n> `App.js`\n\n```react\nimport React from 'react';\nimport './App.scss';\n\nclass App extends React.Component {\n  state = {\n    val: '',\n    list: []\n  }\n\n  handleChange = (event) => {\n    let val = event.target.value;\n    this.setState({\n      val\n    })\n  }\n\n  handleAdd = () => {\n    let { val, list } = this.state;\n    list.push(val);\n    this.setState({\n      list\n    })\n  }\n\n  render() {\n    const { val, list } = this.state;\n    return <div>\n      <h1>HelloWorld</h1>\n      <p>Welcom to my React Demo</p>\n      <input type=\"text\" value={val} onChange={this.handleChange} />\n      <button onClick={this.handleAdd}>Add</button>\n      <ul>\n        {\n          list.map((item) => {\n            return <li>{item}</li>\n          })\n        }\n      </ul>\n    </div>\n  }\n}\n\nexport default App;\n```\n\n"}}]);